 const _20241005OnFaitUnPeuLeM_nage = "{\"parsed\":{\"_path\":\"/fr/20241005-on-fait-un-peu-le-menage\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"On fait un peu le ménage.\",\"description\":\"Comment et pourquoi j'ai migré mon blog de WordPress vers Nuxt et Nuxt Content. Découvrez les raisons de ce changement et les avantages d'une architecture basée sur des fichiers Markdown et Vercel.\",\"image\":\"/images/articles/menage-image.webp\",\"createdAt\":\"2024-10-05\",\"id\":\"2024-10-05T00:00:00.000Z\",\"keywords\":\"migration WordPress, Nuxt 3, Nuxt Content, blog Markdown, Vercel, sécurité WordPress, alternative WordPress, JAMstack, site statique, développement web moderne\",\"summary\":\"Cet article explique ma décision d'abandonner WordPress comme moteur de blog en raison de ses vulnérabilités et limitations, au profit d'une solution plus moderne basée sur Markdown et Vercel. J'y détaille le processus de migration, la nouvelle architecture technique et les prochaines étapes d'amélioration, notamment pour le design et l'intégration d'Open Graph.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"on-fait-un-peu-le-ménage\"},\"children\":[{\"type\":\"text\",\"value\":\"On fait un peu le ménage.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Cela faisait longtemps que je cherchais une bonne excuse pour me débarrasser de WordPress, au moins en tant que moteur de blog. J'ai, pendant longtemps, été un fervent défenseur de ce CMS, mais je dois reconnaître que je me sens de plus en plus mal à l'aise avec lui. Sa simplicité et la facilité à le modifier m'ont offert des possibilités infinies, mais certains points sont désespérants:\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Il ya beaucoup de trop de vulnérabilités,\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"l'avenir du CMS qui dépend de plus en plus du bon vouloir de ses créateurs qui retirent des autorisations de mises à jour de plugins essentiels en fonction de leur bonne relation avec leur créateur,\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je reviens encore, sur les des failles de sécurité non patchées, et ce près d'une année après leur découverte .\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"... (contenu abrégé)\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20241005-on-fait-un-peu-le-ménage.md\",\"_source\":\"content\",\"_file\":\"fr/20241005-on-fait-un-peu-le-ménage.md\",\"_stem\":\"fr/20241005-on-fait-un-peu-le-ménage\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20241005-on-fait-un-peu-le-menage\"}},\"hash\":\"3QyMNCdO1R\"}";

